package dam_A51388.coolweatherapp

import android.content.res.Configuration
import android.os.Bundle
import android.widget.ImageView
import android.widget.TextView
import android.widget.Button
import androidx.appcompat.app.AppCompatActivity
import com.google.gson.Gson
import java.io.InputStreamReader
import java.net.URL

class MainActivity : AppCompatActivity() {
    val day = false;

    override fun onCreate(savedInstanceState: Bundle?) {
        val currentNightMode = resources.configuration.uiMode and Configuration.UI_MODE_NIGHT_MASK
        if (currentNightMode == Configuration.UI_MODE_NIGHT_YES) day = false else day = true


        when (resources.configuration.orientation) {
            Configuration.ORIENTATION_PORTRAIT -> {
                if (day) {
                    setTheme(R.style.Theme_Day)
                } else {
                    setTheme(R.style.Theme_Night)
                }
            }

            Configuration.ORIENTATION_LANDSCAPE -> {
                if (day) {
                    setTheme(R.style.Theme_Day_Land)
                } else {
                    setTheme(R.style.Theme_Night_Land)
                }
            }
        }
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)
    }

    private fun WeatherAPI_Call(lat: Float, long: Float): WeatherData {
        val reqString = buildString {
            append("https://api.open-meteo.com/v1/forecast?")
            append("latitude=${lat}&longitude=${long}&")
            append("daily=uv_index_max,temperature_2m_max,temperature_2m_min,precipitation_probability_max,weather_code,sunset,sunrise,rain_sum,precipitation_hours&")
            append("hourly=temperature_2m,relative_humidity_2m,apparent_temperature,precipitation_probability,precipitation,uv_index,is_day,weather_code&")
            append("current=is_day,rain,snowfall,temperature_2m,apparent_temperature,wind_speed_10m,wind_direction_10m,precipitation,cloud_cover,weather_code,surface_pressure&")
            append("minutely_15=precipitation,apparent_temperature,relative_humidity_2m,temperature_2m,wind_speed_10m,wind_direction_10m,wind_gusts_10m,visibility,is_day")
        }
        val url = URL(reqString.toString())
        url.openStream().use {
            val request = Gson().fromJson(InputStreamReader(it, "UTF-8"), WeatherData::class.java)
            return request
        }
    }


    private fun fetchWeatherData(lat: Float, long: Float): Thread {
        return Thread {
            val weather = WeatherAPI_Call(lat, long)
            updateUI(weather)
        }
    }


    private fun updateUI(request: WeatherData) {
        runOnUiThread {
            try {
                val weatherImage: ImageView = findViewById(R.id.weatherImage)
                val pressureValue: TextView = findViewById(R.id.pressureValue)
                val humidadeValue: TextView = findViewById(R.id.humidadeValue)
                val latitudeValue: TextView = findViewById(R.id.latitudeValue)
                val velocidadeVentoValue: TextView = findViewById(R.id.velocidadeVentoValue)
                val direcaoVentoValue: TextView = findViewById(R.id.direcaoVentoValue)
                val tempoValue: TextView = findViewById(R.id.tempoValue)
                val uvIndexValue: TextView = findViewById(R.id.uvIndexValue)

                // Update pressure
                pressureValue.text = request.hourly.pressure_msl[12].toString() + " hPa"
                // Update humidity (mock data for now)
                humidadeValue.text = "45%"
                // Update latitude
                latitudeValue.text = "38.72°"
                // Update wind speed
                velocidadeVentoValue.text = request.hourly.windspeed_10m[12].toString() + " km/h"
                // Update wind direction (mock data)
                direcaoVentoValue.text = "214°"
                // Update time
                tempoValue.text = "12:00"
                // Update UV Index (mock data)
                uvIndexValue.text = "6"

                // Get weather code and update image
                val mapt = getWeatherCodeMap()
                val wCode = mapt[request.current_weather.weathercode]

                val wImage = when (wCode) {
                    WMO_WeatherCode.CLEAR_SKY,
                    WMO_WeatherCode.MAINLY_CLEAR,
                    WMO_WeatherCode.PARTLY_CLOUDY -> {
                        if (day) wCode?.image + "day" else wCode?.image + "night"
                    }

                    else -> wCode?.image
                }

                val res = getResources()
                weatherImage.setImageDrawable(R.drawable.fog)
                val resID = res.getIdentifier (wImage , " drawable ", getPackageName()) ;
                val drawable = this.getDrawable(resID);
                weatherImage.setImageDrawable(drawable);
                weatherImage.setImageResource(R.drawable.clear_day)

            } catch (e: Exception) {
                e.printStackTrace()
            }
        }
    }

    private fun getWeatherCodeMap(): Map<Int, WMO_WeatherCode> {
        return mapOf(
            0 to WMO_WeatherCode.CLEAR_SKY,
            1 to WMO_WeatherCode.MAINLY_CLEAR,
            2 to WMO_WeatherCode.PARTLY_CLOUDY,
            3 to WMO_WeatherCode.OVERCAST,
            45 to WMO_WeatherCode.FOG_DEPOSITING,
            48 to WMO_WeatherCode.FOG_DEPOSITING,
            51 to WMO_WeatherCode.LIGHT_DRIZZLE,
            53 to WMO_WeatherCode.MODERATE_DRIZZLE,
            55 to WMO_WeatherCode.DENSE_DRIZZLE,
            61 to WMO_WeatherCode.SLIGHT_RAIN,
            63 to WMO_WeatherCode.MODERATE_RAIN,
            65 to WMO_WeatherCode.HEAVY_RAIN,
            71 to WMO_WeatherCode.SLIGHT_SNOW,
            73 to WMO_WeatherCode.MODERATE_SNOW,
            75 to WMO_WeatherCode.HEAVY_SNOW,
            77 to WMO_WeatherCode.SNOW_GRAINS,
            80 to WMO_WeatherCode.SLIGHT_RAIN_SHOWERS,
            81 to WMO_WeatherCode.MODERATE_RAIN_SHOWERS,
            82 to WMO_WeatherCode.VIOLENT_RAIN_SHOWERS,
            85 to WMO_WeatherCode.SLIGHT_SNOW_SHOWERS,
            86 to WMO_WeatherCode.HEAVY_SNOW_SHOWERS,
            95 to WMO_WeatherCode.THUNDERSTORM,
            96 to WMO_WeatherCode.THUNDERSTORM_WITH_HAIL,
            99 to WMO_WeatherCode.THUNDERSTORM_WITH_HAIL
        )
    }

    fun onUpdateClick(v: android.view.View) {
        // Fetch weather for Lisboa (default coordinates)
        fetchWeatherData(38.7223f, -9.1393f).start()
    }
}

}

package dam_A51388.coolweatherapp

import android.content.res.Configuration
import android.os.Bundle
import android.widget.ImageView
import android.widget.TextView
import android.widget.Button
import androidx.appcompat.app.AppCompatActivity
import com.google.gson.Gson
import java.io.InputStreamReader
import java.net.URL

class MainActivity : AppCompatActivity() {

    private var day: Boolean = true

    override fun onCreate(savedInstanceState: Bundle?) {
        val currentNightMode = resources.configuration.uiMode and Configuration.UI_MODE_NIGHT_MASK
        day = if (currentNightMode == Configuration.UI_MODE_NIGHT_YES) false else true

        when (resources.configuration.orientation) {
            Configuration.ORIENTATION_PORTRAIT -> {
                if (day) {
                    setTheme(R.style.Theme_Day)
                } else {
                    setTheme(R.style.Theme_Night)
                }
            }

            Configuration.ORIENTATION_LANDSCAPE -> {
                if (day) {
                    setTheme(R.style.Theme_Day_Land)
                } else {
                    setTheme(R.style.Theme_Night_Land)
                }
            }
        }
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)

        // Setup update button
        val updateButton: Button = findViewById(R.id.btn_update)
        updateButton.setOnClickListener {
            fetchWeatherData(38.7223f, -9.1393f).start()
        }

        // Fetch initial weather data
        fetchWeatherData(38.7223f, -9.1393f).start()
    }

    private fun WeatherAPI_Call(lat: Float, long: Float): WeatherData {
        val reqString = buildString {
            append("https://api.open-meteo.com/v1/forecast?")
            append("latitude=${lat}&longitude=${long}&")
            append("daily=uv_index_max,temperature_2m_max,temperature_2m_min,precipitation_probability_max,weather_code,sunset,sunrise,rain_sum,precipitation_hours&")
            append("hourly=temperature_2m,relative_humidity_2m,apparent_temperature,precipitation_probability,precipitation,uv_index,is_day,weather_code&")
            append("current=is_day,rain,snowfall,temperature_2m,apparent_temperature,wind_speed_10m,wind_direction_10m,precipitation,cloud_cover,weather_code,surface_pressure&")
            append("minutely_15=precipitation,apparent_temperature,relative_humidity_2m,temperature_2m,wind_speed_10m,wind_direction_10m,wind_gusts_10m,visibility,is_day")
        }
        val url = URL(reqString.toString())
        url.openStream().use {
            val request = Gson().fromJson(InputStreamReader(it, "UTF-8"), WeatherData::class.java)
            return request
        }
    }

    private fun fetchWeatherData(lat: Float, long: Float): Thread {
        return Thread {
            try {
                val weather = WeatherAPI_Call(lat, long)
                updateUI(weather)
            } catch (e: Exception) {
                e.printStackTrace()
            }
        }
    }

    private fun updateUI(request: WeatherData) {
        runOnUiThread {
            try {
                val weatherImage: ImageView = findViewById(R.id.weatherImage)
                val pressureValue: TextView = findViewById(R.id.pressureValue)
                val humidadeValue: TextView = findViewById(R.id.humidadeValue)
                val latitudeValue: TextView = findViewById(R.id.latitudeValue)
                val velocidadeVentoValue: TextView = findViewById(R.id.velocidadeVentoValue)
                val direcaoVentoValue: TextView = findViewById(R.id.direcaoVentoValue)
                val tempoValue: TextView = findViewById(R.id.tempoValue)
                val uvIndexValue: TextView = findViewById(R.id.uvIndexValue)

                // Update pressure
                pressureValue.text = request.current_weather.surface_pressure.toString() + " hPa"

                // Update humidity
                humidadeValue.text = request.hourly.relative_humidity_2m[12].toString() + "%"

                // Update latitude
                latitudeValue.text = request.latitude.toString() + "°"

                // Update wind speed
                velocidadeVentoValue.text = request.current_weather.windspeed.toString() + " km/h"

                // Update wind direction
                direcaoVentoValue.text = request.current_weather.winddirection.toString() + "°"

                // Update time
                tempoValue.text = "12:00"

                // Update UV Index
                uvIndexValue.text = request.hourly.uv_index[12].toString()

                // Get weather code and update image
                val mapt = getWeatherCodeMap()
                val wCode = mapt[request.current_weather.weathercode]

                val wImage = when (wCode) {
                    WMO_WeatherCode.CLEAR_SKY,
                    WMO_WeatherCode.MAINLY_CLEAR,
                    WMO_WeatherCode.PARTLY_CLOUDY -> if (day) wCode?.image + "day" else wCode?.image + "night"
                    else -> wCode?.image ?: "clear_day"
                }

                val res = resources
                val resID = res.getIdentifier(wImage, "drawable", packageName)
                if (resID != 0) {
                    val drawable = getDrawable(resID)
                    weatherImage.setImageDrawable(drawable)
                } else {
                    weatherImage.setImageResource(R.drawable.clear_day)
                }
            } catch (e: Exception) {
                e.printStackTrace()
            }
        }
    }

    private fun getWeatherCodeMap(): Map<Int, WMO_WeatherCode> {
        val weatherMap = HashMap<Int, WMO_WeatherCode>()
        WMO_WeatherCode.values().forEach {
            weatherMap[it.code] = it
        }
        return weatherMap
    }

    fun onUpdateClick(v: android.view.View) {
        fetchWeatherData(38.7223f, -9.1393f).start()
    }
}

package dam_A51388.coolweatherapp

// ─── Raiz do JSON ────────────────────────────────────────────────────────────
data class WeatherData(
    var latitude: Double,// era String → API devolve número
    var longitude: Double,// era String → API devolve número
    var timezone: String,
    var current: CurrentWeather,// era current_weather → novo formato API
    var hourly: Hourly
)

// ─── Bloco "current" ─────────────────────────────────────────────────────────
data class CurrentWeather(
    var temperature_2m: Float, // era temperature
    var apparent_temperature: Float,// sensação térmica
    var wind_speed_10m: Float,// era windspeed
    var wind_direction_10m: Int,// era winddirection
    var weather_code: Int,// era weathercode
    var surface_pressure: Double,// substitui pressure_msl do hourly
    var cloud_cover: Int,
    var precipitation: Float,
    var rain: Float,
    var snowfall: Float,
    var is_day: Int,// 1 = dia, 0 = noite → usar para tema
    var time: String
)

// ─── Bloco "hourly" ──────────────────────────────────────────────────────────
data class Hourly(
    var time: ArrayList<String>,
    var temperature_2m: ArrayList<Float>,
    var apparent_temperature: ArrayList<Float>,
    var relative_humidity_2m: ArrayList<Int>,
    var precipitation_probability: ArrayList<Int>,
    var precipitation: ArrayList<Float>,
    var weather_code: ArrayList<Int>,// era weathercode
    var uv_index: ArrayList<Float>,
    var is_day: ArrayList<Int>,
    var pressure_msl: ArrayList<Double>//não está no URL; usa surface_pressure do current
)

// ─── Códigos WMO ─────────────────────────────────────────────────────────────
enum class WMO_WeatherCode(var code: Int, var image: String) {
    CLEAR_SKY(0, "clear_"),
    MAINLY_CLEAR(1, "mostly_clear_"),
    PARTLY_CLOUDY(2, "partly_cloudy_"),
    OVERCAST(3, "cloudy"),
    FOG(45, "fog"),
    DEPOSITING_RIME_FOG(48, "fog"),
    DRIZZLE_LIGHT(51, "drizzle"),
    DRIZZLE_MODERATE(53, "drizzle"),
    DRIZZLE_DENSE(55, "drizzle"),
    FREEZING_DRIZZLE_LIGHT(56, "freezing_drizzle"),
    FREEZING_DRIZZLE_DENSE(57, "freezing_drizzle"),
    RAIN_SLIGHT(61, "rain_light"),
    RAIN_MODERATE(63, "rain"),
    RAIN_HEAVY(65, "rain_heavy"),
    FREEZING_RAIN_LIGHT(66, "freezing_rain_light"),
    FREEZING_RAIN_HEAVY(67, "freezing_rain_heavy"),
    SNOW_FALL_SLIGHT(71, "snow_light"),
    SNOW_FALL_MODERATE(73, "snow"),
    SNOW_FALL_HEAVY(75, "snow_heavy"),
    SNOW_GRAINS(77, "snow"),
    RAIN_SHOWERS_SLIGHT(80, "rain_light"),
    RAIN_SHOWERS_MODERATE(81, "rain"),
    RAIN_SHOWERS_VIOLENT(82, "rain_heavy"),
    SNOW_SHOWERS_SLIGHT(85, "snow_light"),
    SNOW_SHOWERS_HEAVY(86, "snow_heavy"),
    THUNDERSTORM_SLIGHT_MODERATE(95, "tstorm"),
    THUNDERSTORM_HAIL_SLIGHT(96, "tstorm"),
    THUNDERSTORM_HAIL_HEAVY(99, "tstorm")
}

fun getWeatherCodeMap(): Map<Int, WMO_WeatherCode> {
    val weatherMap = HashMap<Int, WMO_WeatherCode>()
    WMO_WeatherCode.values().forEach { weatherMap[it.code] = it }
    return weatherMap
}

package dam_A51388.coolweatherapp

// ─── Raiz do JSON ────────────────────────────────────────────────────────────
data class WeatherData(
    var latitude: Double,
    var longitude: Double,
    var timezone: String,
    var current_weather: CurrentWeather,
    var hourly: Hourly
)

// ─── Bloco "current" ─────────────────────────────────────────────────────────
data class CurrentWeather(
    var temperature: Float,
    var windspeed: Float,
    var winddirection: Int,
    var weathercode: Int,
    var time: String
)

// ─── Bloco "hourly" ──────────────────────────────────────────────────────────
data class Hourly(
    var time: ArrayList<String>,
    var temperature_2m: ArrayList<Float>,
    var weathercode: ArrayList<Int>,
    var pressure_msl: ArrayList<Double>
)

// ─── Códigos WMO ─────────────────────────────────────────────────────────────
enum class WMO_WeatherCode(var code: Int, var image: String) {
    CLEAR_SKY(0, "clear_"),
    MAINLY_CLEAR(1, "mostly_clear_"),
    PARTLY_CLOUDY(2, "partly_cloudy_"),
    OVERCAST(3, "cloudy"),
    FOG(45, "fog"),
    DEPOSITING_RIME_FOG(48, "fog"),
    DRIZZLE_LIGHT(51, "drizzle"),
    DRIZZLE_MODERATE(53, "drizzle"),
    DRIZZLE_DENSE(55, "drizzle"),
    FREEZING_DRIZZLE_LIGHT(56, "freezing_drizzle"),
    FREEZING_DRIZZLE_DENSE(57, "freezing_drizzle"),
    RAIN_SLIGHT(61, "rain_light"),
    RAIN_MODERATE(63, "rain"),
    RAIN_HEAVY(65, "rain_heavy"),
    FREEZING_RAIN_LIGHT(66, "freezing_rain_light"),
    FREEZING_RAIN_HEAVY(67, "freezing_rain_heavy"),
    SNOW_FALL_SLIGHT(71, "snow_light"),
    SNOW_FALL_MODERATE(73, "snow"),
    SNOW_FALL_HEAVY(75, "snow_heavy"),
    SNOW_GRAINS(77, "snow"),
    RAIN_SHOWERS_SLIGHT(80, "rain_light"),
    RAIN_SHOWERS_MODERATE(81, "rain"),
    RAIN_SHOWERS_VIOLENT(82, "rain_heavy"),
    SNOW_SHOWERS_SLIGHT(85, "snow_light"),
    SNOW_SHOWERS_HEAVY(86, "snow_heavy"),
    THUNDERSTORM_SLIGHT_MODERATE(95, "tstorm"),
    THUNDERSTORM_HAIL_SLIGHT(96, "tstorm"),
    THUNDERSTORM_HAIL_HEAVY(99, "tstorm")
}

fun getWeatherCodeMap(): Map<Int, WMO_WeatherCode> {
    val weatherMap = HashMap<Int, WMO_WeatherCode>()
    WMO_WeatherCode.values().forEach {
        weatherMap[it.code] = it
    }
    return weatherMap
}
